const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const snapshotPath = path.join(vaultPath, 'JobFilter', 'Agent Runs', '.material-prices-prev.json');
const current = $input.first().json || {};
let prev = null;
if (fs.existsSync(snapshotPath)) { try { prev = JSON.parse(fs.readFileSync(snapshotPath, 'utf-8')); } catch {} }
const flatten = (obj) => {
  const out = {};
  const walk = (o, prefix='') => {
    if (o && typeof o === 'object') {
      for (const k of Object.keys(o)) {
        const key = prefix ? prefix + '.' + k : k;
        const v = o[k];
        if (typeof v === 'number') out[key] = v;
        else if (v && typeof v === 'object') walk(v, key);
      }
    }
  };
  walk(obj);
  return out;
};
const curFlat = flatten(current);
const prevFlat = prev ? flatten(prev) : {};
const spikes = [];
const threshold = 0.05;
for (const k of Object.keys(curFlat)) {
  const c = curFlat[k];
  const p = prevFlat[k];
  if (p && p > 0) {
    const pct = (c - p) / p;
    if (Math.abs(pct) >= threshold) spikes.push({ key: k, prev: p, current: c, pct: Number((pct * 100).toFixed(2)) });
  }
}
spikes.sort((a, b) => Math.abs(b.pct) - Math.abs(a.pct));
fs.mkdirSync(path.dirname(snapshotPath), { recursive: true });
fs.writeFileSync(snapshotPath, JSON.stringify(current, null, 2));
return [{ json: { spikes, spikeCount: spikes.length, hasSpikes: spikes.length > 0, current, threshold } }];
